const ontologyText = $json.ontology_text || '';

//
// ======================================================
// EXTRAER ONTOLOGY TYPE
// ======================================================
//

const ontologyTypeMatch = ontologyText.match(
  /OntologyType:\s*([A-Za-z0-9_-]+)/i
);

const ontologyType = ontologyTypeMatch
  ? ontologyTypeMatch[1].trim().toLowerCase()
  : 'unknown';

//
// ======================================================
// NORMALIZACIÓN
// ======================================================
//

const normalized = ontologyText
  .replace(/\r\n/g, '\n')
  .trim();

//
// ======================================================
// UTILIDADES
// ======================================================
//

function extractSingleValue(block, fieldName) {

  const regex = new RegExp(
    `^${fieldName}:\\s*(.*)$`,
    'mi'
  );

  const match = block.match(regex);

  return match
    ? match[1].trim()
    : null;
}

function extractSectionList(block, sectionName) {

  const lines = block.split('\n');

  const values = [];

  let insideSection = false;

  for (const line of lines) {

    const trimmed = line.trim();

    //
    // Inicio de sección
    //
    if (
      trimmed.toLowerCase() ===
      `${sectionName.toLowerCase()}:`
    ) {
      insideSection = true;
      continue;
    }

    //
    // Cambio a otra sección
    //
    if (
      insideSection &&
      /^[a-zA-Z_]+:\s*/.test(trimmed)
    ) {
      break;
    }

    //
    // Item lista
    //
    if (
      insideSection &&
      trimmed.startsWith('- ')
    ) {
      values.push(
        trimmed.substring(2).trim()
      );
    }
  }

  return values;
}

function extractMultilineText(
  block,
  sectionName
) {

  const lines = block.split('\n');

  const values = [];

  let insideSection = false;

  for (const line of lines) {

    const trimmed = line.trim();

    if (
      trimmed.toLowerCase() ===
      `${sectionName.toLowerCase()}:`
    ) {
      insideSection = true;
      continue;
    }

    if (
      insideSection &&
      /^[a-zA-Z_]+:\s*/.test(trimmed)
    ) {
      break;
    }

    if (insideSection) {

      if (
        trimmed &&
        !trimmed.startsWith('- ')
      ) {
        values.push(trimmed);
      }
    }
  }

  return values.join(' ').trim();
}

//
// ======================================================
// DIVIDIR POR CONCEPTOS
// ======================================================
//

const rawSections = normalized.split(
  /^##\s+/gm
);

const concepts = [];

for (const section of rawSections) {

  let block = section.trim();

  if (!block) {
    continue;
  }

  //
  // Ignorar cabecera global
  //
  if (
    block.startsWith('# Home Insurance Ontology') ||
    block.includes('OntologyType:')
  ) {
    continue;
  }

  //
  // Limpieza
  //
  block = block
    .replace(/---+/g, '')
    .trim();

  const lines = block.split('\n');

  const conceptId =
    (lines[0] || '').trim();

  if (!conceptId) {
    continue;
  }

  //
  // ======================================================
  // EXTRAER CAMPOS
  // ======================================================
  //

  const riskField =
    extractSingleValue(
      block,
      'risk_field'
    );

  const dataType =
    extractSingleValue(
      block,
      'data_type'
    );

  const meaning =
    extractSingleValue(
      block,
      'meaning'
    ) ||
    extractMultilineText(
      block,
      'meaning'
    );

  const interpretation =
    extractMultilineText(
      block,
      'interpretation'
    );

  const aliases =
    extractSectionList(
      block,
      'aliases'
    );

  const contractualExamples =
    extractSectionList(
      block,
      'contractual_examples'
    );

  const negativeAliases =
    extractSectionList(
      block,
      'negative_aliases'
    );

  //
  // ======================================================
  // TEXTO PARA EMBEDDINGS
  // ======================================================
  //

  const searchableParts = [

    ...(aliases || []),

    ...(contractualExamples || []),

    meaning || '',

    interpretation || ''

  ];

  const searchableText =
    searchableParts
      .filter(Boolean)
      .join('\n')
      .trim();

  //
  // Estadísticas
  //
  const wordCount =
    searchableText
      .split(/\s+/)
      .filter(Boolean)
      .length;

  concepts.push({
    json: {

      //
      // Identificación
      //
      concept_id: conceptId,
      concept_key:
        `${ontologyType}:${conceptId}`,
      ontology_type:
        ontologyType,

      //
      // Metadatos
      //
      risk_field:
        riskField,

      data_type:
        dataType,

      aliases,

      contractual_examples:
        contractualExamples,

      negative_aliases:
        negativeAliases,

      meaning,

      interpretation,

      //
      // Textos
      //
      ontology_raw:
        block,

      searchable_text:
        searchableText,

      //
      // Compatibilidad
      // (puedes mantenerlo
      // mientras migras)
      //
      ontology_text:
        searchableText,

      //
      // Métricas
      //
      concept_words:
        wordCount,

      concept_length:
        searchableText.length

    }
  });
}

//
// ======================================================
// ORDEN CONSISTENTE
// ======================================================
//

concepts.sort((a, b) =>
  a.json.concept_id.localeCompare(
    b.json.concept_id
  )
);

return concepts;

const splitter = $('Ontology Splitter').item.json;

const conceptId = splitter.concept_id;
const ontologyType = splitter.ontology_type;

const embedding = $json.embedding;

function deterministicId(str) {
  let hash = 0;

  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }

  return Math.abs(hash);
}

const conceptKey = `${ontologyType}:${conceptId}`;
const pointId = deterministicId(conceptKey);

return {
  json: {
    points: [
      {
        id: pointId,

        vector: embedding,

        payload: {

          // ==================================================
          // IDENTIFICACIÓN
          // ==================================================

          concept_key: conceptKey,
          concept_id: conceptId,
          ontology_type: ontologyType,

          // ==================================================
          // METADATOS ESTRUCTURADOS
          // ==================================================

          risk_field:
            splitter.risk_field || null,

          data_type:
            splitter.data_type || null,

          aliases:
            splitter.aliases || [],

          contractual_examples:
            splitter.contractual_examples || [],

          negative_aliases:
            splitter.negative_aliases || [],

          meaning:
            splitter.meaning || null,

          interpretation:
            splitter.interpretation || null,

          // ==================================================
          // TEXTOS
          // ==================================================

          // Bloque completo original
          ontology_raw:
            splitter.ontology_raw || null,

          // Texto optimizado para embeddings
          searchable_text:
            splitter.searchable_text || null,

          // Texto exacto utilizado para generar el embedding
          embedding_source_text:
            splitter.searchable_text || null,

          // Compatibilidad con versiones anteriores
          ontology_text:
            splitter.searchable_text || null,

          // ==================================================
          // MÉTRICAS
          // ==================================================

          concept_words:
            splitter.concept_words || 0,

          concept_length:
            splitter.concept_length || 0
        }
      }
    ]
  }
};
